1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] } | { op: "claim" };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const FIRST_INSURANCE_MULTIPLIER = 1.1;
15	const PROCESSING_FEE = 5;
16	
17	const ceilToWholeG = (amount: number): number =>
18	  Math.ceil(Math.round(amount * 100) / 100);
19	
20	const COMPONENT_BUNDLE_PRICE = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const itemMultiplier = (item: Item): number => {
24	  let m = 1;
25	  if (item.cursed) m *= 1.5;
26	  if ((item.enchantment ?? 0) >= 5) m *= 1.3;
27	  return m;
28	};
29	
30	const sumItemsAtUnitPrice = (items: Item[], unitPrice: number): number =>
31	  items.reduce((sum, item) => sum + unitPrice * itemMultiplier(item), 0);
32	
33	const baseForGroup = (type: string, group: Item[]): number => {
34	  const unitPrice = BASE_PREMIUM[type] ?? 0;
35	  if (!COMPONENT_TYPES.has(type)) {
36	    return sumItemsAtUnitPrice(group, unitPrice);
37	  }
38	  const bundleCount = Math.floor(group.length / 3);
39	  const singles = group.slice(bundleCount * 3);
40	  return bundleCount * COMPONENT_BUNDLE_PRICE + sumItemsAtUnitPrice(singles, unitPrice);
41	};
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const list = groups.get(item.type) ?? [];
47	    list.push(item);
48	    groups.set(item.type, list);
49	  }
50	  return groups;
51	};
52	
53	const customerMultiplier = (customer: Scenario["customer"]): number =>
54	  customer.yearsWithMHPCO >= 2 ? 0.8 : 1;
55	
56	const quote = (items: Item[], customer: Scenario["customer"]): number => {
57	  const base = [...groupByType(items)].reduce(
58	    (sum, [type, group]) => sum + baseForGroup(type, group),
59	    0,
60	  );
61	  const adjusted = base * customerMultiplier(customer) * FIRST_INSURANCE_MULTIPLIER;
62	  return ceilToWholeG(adjusted) + PROCESSING_FEE;
63	};
64	
65	const processStep = (step: Step, customer: Scenario["customer"]): unknown =>
66	  step.op === "quote" ? { premium: quote(step.items, customer) } : {};
67	
68	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
69	  results: scenario.steps.map((step) => processStep(step, scenario.customer)),
70	});
